const cataloguePage = $input.first().json;
const InstancesID = $('04 set instances after split').first().json.idInstances;
const Nb_users = $('04 set instances after split').first().json.Nb_users;

// Extraire le Responsable (propriété people)
const ResponsablesArray = cataloguePage.properties?.Responsable?.people || [];
const Responsables = ResponsablesArray.length > 0 ? ResponsablesArray[0].id : null;

// Extraire les IDs utilisateurs (rollup de people avec show_unique)
const userRollup = cataloguePage.properties?.['ID utilisateur']?.rollup;
let userIds = [];

if (userRollup?.type === 'array' && userRollup.array) {
  const allUserIds = userRollup.array.flatMap(item => {
    if (item.type === 'people' && item.people) {
      return item.people.map(person => person.id);
    }
    return [];
  });
  userIds = [...new Set(allUserIds)];
}

// Extraire les documents (relation Master Documentations Entreprise)
const documentsRelation = cataloguePage.properties?.['Master Documentations Entreprise']?.relation || [];
const documents = documentsRelation.map(rel => rel.id);

// Extraire le nom (propriété title)
const titleArray = cataloguePage.properties?.Nom?.title || [];
const catalogueName = titleArray.length > 0 ? titleArray[0].plain_text : '';

// Extraire l'ID de "Nos Formations"
const formationsRelation = cataloguePage.properties?.['Nos Formations']?.relation || [];
const formationId = formationsRelation.length > 0 ? formationsRelation[0].id : null;

// Extraire le Lieu (propriété place)
const lieuProperty = cataloguePage.properties?.Lieu?.place || null;
const lieu = lieuProperty ? {
  lat: lieuProperty.lat,
  lon: lieuProperty.lon,
  name: lieuProperty.name,
  address: lieuProperty.address,
  aws_place_id: lieuProperty.aws_place_id,
  google_place_id: lieuProperty.google_place_id
} : null;

// Retourner un item par utilisateur avec toutes les infos
return userIds.map((userId, index) => ({
  json: {
    userId: userId,
    userIndex: index + 1,
    totalUsers: userIds.length,
    documents: documents,
    totalDocuments: documents.length,
    hasDocuments: documents.length > 0,
    cataloguePageId: cataloguePage.id,
    catalogueName: catalogueName,
    Responsable: Responsables,
    formationId: formationId,
    lieu: lieu, // Objet lieu complet
    InstancesID: InstancesID,
    Nb_users: Nb_users,
  }
}));

// Récupérer le premier item complet
const firstItem = $input.first().json;

// Extraire l'identifiant unique (format Notion unique_id)
const identifiantObj = firstItem.properties?.Identifiant || firstItem.Identifiant;
const prefix = identifiantObj?.unique_id?.prefix || '';
const number = identifiantObj?.unique_id?.number || '';
const idUSER = $input.first().json.properties.Utilisateur.people[0].id || '';
const identifiant = `${prefix}${number}`;

// Extraire le nom
const name = $('09 - Set Inscription').first().json.name || firstItem.name || '';

// Créer le texte concaténé
const concatenatedText = `${name} ${identifiant}`;

return [{
  json: {
    name_employe: idUSER, // Conserver l'ID si nécessaire
    identifiant: identifiant, // "EMP1"
    name: name,
    concatenatedText: concatenatedText, // "John Doe EMP1"
  }
}];

