// Récupérer les infos du Split in Batches
const splitInfo = $('Split Instances').context;
const splitData = splitInfo?.nodesData?.['Split Instances']?.[0];
const batchSize = splitData?.batchSize || 1;
const currentBatchIndex = splitData?.batchIndex || 0;
const InstancesID = $('17 Merge').first().json.InstancesID;
const Totalemail = $('17 Merge').first().json.totalEmails;

// Calculer l'offset basé sur le batch
const batchOffset = currentBatchIndex * batchSize;

// Index dans le batch actuel
const items = $input.all();
const localIndex = items.findIndex(item => 
  JSON.stringify(item.json) === JSON.stringify($input.item.json)
);

const safeLocalIndex = localIndex >= 0 ? localIndex : 0;

// Index global
const globalIndex = batchOffset + safeLocalIndex;

// Valeur initiale
const initialValue = $('17 Merge').first().json.Nb_users || 0;
const incrementValue = initialValue + globalIndex + 1; // ← +1 ici

return [{
  json: {
    ...$input.item.json,
    incrementValue: incrementValue,
    itemPosition: globalIndex + 1,
    InstancesID: InstancesID,
    Totalemail: Totalemail,
  }
}];

// Récupérer les infos du Split in Batches
const splitInfo = $('Split Instances').context;
const splitData = splitInfo?.nodesData?.['Split Instances']?.[0];
const batchSize = splitData?.batchSize || 1;
const currentBatchIndex = splitData?.batchIndex || 0;
const InstancesID = $('09 - Set Inscription').first().json.InstancesID;

// Calculer l'offset basé sur le batch
const batchOffset = currentBatchIndex * batchSize;

// Index dans le batch actuel
const items = $input.all();
const localIndex = items.findIndex(item => 
  JSON.stringify(item.json) === JSON.stringify($input.item.json)
);

// Sécurité : si localIndex n'est pas trouvé
const safeLocalIndex = localIndex >= 0 ? localIndex : 0;

// Index global
const globalIndex = batchOffset + safeLocalIndex;

// Valeur initiale
const initialValue = 0;
const incrementerror = initialValue + globalIndex;

return [{
  json: {
    ...$input.item.json,
    incrementerror: incrementerror,
    itemerror: globalIndex + 1,
    InstancesID: InstancesID,
  }
}];

const pageId = $input.first().json.body.data.id;

// Le node Notion Get Page suivant récupérera la page à jour
return [{
  json: {
    pageId: pageId
  }
}];
